using System;
using System.Data.SqlClient;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.Extensions.Logging;

public static class AzureSqlQueryFunction
{
    [FunctionName("AzureSqlQuery")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger logger)
    {
        string tableName = Environment.GetEnvironmentVariable("tableName");
        string connectionString = Environment.GetEnvironmentVariable("connectionString");

        string databaseName = req.Query["database"];
        string filterColumn = req.Query["filterColumn"];
        string filterOperator = req.Query["filterOperator"];
        string filterValue = req.Query["filterValue"];

        if (string.IsNullOrEmpty(databaseName) || 
            string.IsNullOrEmpty(filterColumn) || 
            string.IsNullOrEmpty(filterOperator) || 
            string.IsNullOrEmpty(filterValue))
        {
            return new BadRequestResult();
        }

        try
        {
            using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();

            string query = $"SELECT * FROM {databaseName}.{tableName} WHERE {filterColumn} {filterOperator} '{filterValue}'";

            var command = connection.CreateCommand();
            command.CommandText = query;

            var reader = await command.ExecuteReaderAsync();

            while (await reader.ReadAsync())
            {
                logger.LogInformation($"Read {reader[0]}");
            }
        }
        catch (Exception ex)
        {
            return new StatusCodeResult(500);
        }

        return new OkObjectResult(new { result = "Success" });
    }
}